import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import retrofit2.http.Header

// Define a Retrofit API interface for user profiles
interface UserApi {
    @GET("users")
    suspend fun getUsers(@Header("Authorization") token: String): List<UserProfile>
}

// Data class to represent a user profile
data class UserProfile(val id: Int, val name: String, val email: String)

// Interceptor to add the authorization header
class AuthInterceptor(private val tokenProvider: TokenProvider) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): okhttp3.Response {
        val request = chain.request().newBuilder()
            .header("Authorization", "Bearer ${tokenProvider.getToken()}")
            .build()
        return chain.proceed(request)
    }
}

// Simple interface to provide tokens
interface TokenProvider {
    fun getToken(): String
}

// Class to manage Retrofit instance
class NetworkModule(private val tokenProvider: TokenProvider, private val baseUrl: String) {

    private val client = OkHttpClient.Builder()
        .addInterceptor(AuthInterceptor(tokenProvider))
        .build()

    private val retrofit = Retrofit.Builder()
        .baseUrl(baseUrl)
        .client(client)
        .addConverterFactory(GsonConverterFactory.create())
        .build()

    fun getUserApi(): UserApi {
        return retrofit.create(UserApi::class.java)
    }
}

// Example usage
fun main() {
    // Mock implementation of TokenProvider
    object : TokenProvider {
        override fun getToken(): String = "your-auth-token"
    }

    val networkModule = NetworkModule(
        tokenProvider = mockTokenProvider,
        baseUrl = "https://api.example.com/"
    )

    val userApi = networkModule.getUserApi()

    // Example of fetching users
    runBlocking {
        val users = userApi.getUsers(mockTokenProvider.getToken())
        users.forEach { println("${it.name}, ${it.email}") }
    }
}